export default function StartScreen() {
  const [newName, setNewName] = useState('')
  const [showInput, setShowInput] = useState(false)
  const {
    players,
    addPlayer,
    removePlayer,
    setPlayerGender,
    settings,
    updateSettings,
    setScreen,
  } = useGameStore()
  const l = t(settings.language)

  const handleAdd = () => {
    const trimmed = newName.trim()
    if (trimmed) {
      addPlayer(trimmed)
      setNewName('')
      setShowInput(false)
    }
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleAdd()
  }

  const canStart = players.length >= 2

  return (
    <div
      className="flex flex-col h-dvh w-full relative"
      style={{
        paddingTop: 'max(env(safe-area-inset-top), 12px)',
        paddingBottom: 'max(env(safe-area-inset-bottom), 12px)',
      }}
    >
      {/* Background photo */}
      <div
        className="absolute inset-0 -z-10"
        style={{
          backgroundImage: 'url(/bg-sunset.jpg)',
          backgroundSize: 'cover',
          backgroundPosition: 'center',
        }}
      />

      {/* Header */}
      <div className="flex items-center justify-between px-4 py-2 shrink-0">
        <button className="w-12 h-12 flex items-center justify-center">
          <ArrowLeft className="w-8 h-8 text-white" />
        </button>
        <button
          onClick={() => setScreen('settings')}
          className="w-12 h-12 flex items-center justify-center"
        >
          <Settings className="w-7 h-7 text-white" />
        </button>
      </div>

      {/* Player list */}
      <div className="flex-1 overflow-y-auto px-4 py-1 flex flex-col gap-3">
        {players.map((p) => (
          <div key={p.id} className="flex items-center gap-3">
            {/* Trash button */}
            <button
              onClick={() => removePlayer(p.id)}
              className="w-14 h-14 bg-black rounded-2xl flex items-center justify-center shrink-0"
            >
              <Trash2 className="w-6 h-6 text-white" />
            </button>

            {/* Name pill */}
            <div
              className="flex-1 h-14 flex items-center justify-center rounded-full px-4"
              style={{
                background: 'linear-gradient(90deg, #0a0a0a 0%, #2e2e2e 100%)',
              }}
            >
              <span className="text-white font-bold text-xl tracking-wide">
                {p.name}
              </span>
            </div>

            {/* Gender toggle */}
            <GenderToggle
              gender={p.gender}
              onChange={(g) => setPlayerGender(p.id, g)}
            />
          </div>
        ))}

        {/* Inline input */}
        {showInput && (
          <div className="flex items-center gap-2">
            <div className="w-14 shrink-0" />
            <input
              autoFocus
              value={newName}
              onChange={(e) => setNewName(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={l.enterName}
              maxLength={20}
              className="flex-1 h-14 bg-black/80 rounded-full px-5 outline-none text-white text-xl font-bold placeholder:text-white/40 border border-white/20 focus:border-white/50"
            />
            <button
              onClick={handleAdd}
              className="h-14 w-16 bg-black rounded-2xl text-white font-bold shrink-0"
            >
              OK
            </button>
          </div>
        )}
      </div>

      {/* Bottom controls */}
      <div className="shrink-0 px-4 flex flex-col gap-3 pb-2">
        {/* Roulette row */}
        <div className="flex items-center bg-black rounded-full px-4 py-3 gap-3">
          {/* Wheel icon */}
          <svg viewBox="0 0 24 24" className="w-7 h-7 shrink-0" fill="none">
            <circle cx="12" cy="12" r="10" stroke="white" strokeWidth="1.5" />
            <circle cx="12" cy="12" r="2.5" stroke="white" strokeWidth="1.5" />
            <line x1="12" y1="2" x2="12" y2="9.5" stroke="white" strokeWidth="1.5" />
            <line x1="12" y1="14.5" x2="12" y2="22" stroke="white" strokeWidth="1.5" />
            <line x1="2" y1="12" x2="9.5" y2="12" stroke="white" strokeWidth="1.5" />
            <line x1="14.5" y1="12" x2="22" y2="12" stroke="white" strokeWidth="1.5" />
            <line x1="5.64" y1="5.64" x2="9.17" y2="9.17" stroke="white" strokeWidth="1.5" />
            <line x1="14.83" y1="14.83" x2="18.36" y2="18.36" stroke="white" strokeWidth="1.5" />
            <line x1="18.36" y1="5.64" x2="14.83" y2="9.17" stroke="white" strokeWidth="1.5" />
            <line x1="9.17" y1="14.83" x2="5.64" y2="18.36" stroke="white" strokeWidth="1.5" />
          </svg>
          <span className="flex-1 font-bold text-lg" style={{ color: '#4dd0e1' }}>
            {l.roulette}
          </span>
          <label className="relative inline-flex items-center cursor-pointer shrink-0">
            <input
              type="checkbox"
              checked={settings.randomWheel}
              onChange={(e) => updateSettings({ randomWheel: e.target.checked })}
              className="sr-only peer"
            />
            <div className="w-14 h-7 bg-gray-600 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[3px] after:start-[3px] after:bg-white after:rounded-full after:h-[22px] after:w-[22px] after:transition-all peer-checked:bg-green-500" />
          </label>
        </div>

        {/* Start + Add row */}
        <div className="flex items-center gap-3">
          <button
            onClick={() => { if (canStart) setScreen('game') }}
            disabled={!canStart}
            className={`flex-1 h-16 rounded-full text-2xl font-bold transition-all ${
              canStart
                ? 'bg-black text-white active:scale-[0.97]'
                : 'bg-black/60 text-white/50 cursor-not-allowed'
            }`}
          >
            {canStart ? l.start : l.min2players}
          </button>
          {!showInput && (
            <button
              onClick={() => setShowInput(true)}
              className="w-16 h-16 bg-black rounded-2xl flex items-center justify-center shrink-0 active:scale-95 transition-transform"
            >
              <svg viewBox="0 0 24 24" className="w-8 h-8" fill="none">
                <path d="M12 5v14M5 12h14" stroke="white" strokeWidth="3" strokeLinecap="round" />
              </svg>
            </button>
          )}
        </div>
      </div>
    </div>
  )
}
